Page({
  data: {
    base64Content: 'data:image/jpg;base64,',
    imageUrl: '',
    isLoading: false
  },

  onInputChange(e) {
    this.setData({
      base64Content: e.detail.value
    });
  },

  convertToImage() {
    const base64 = this.data.base64Content.trim();
    if (!base64) {
      wx.showToast({
        title: '请输入base64内容',
        icon: 'none'
      });
      return;
    }

    this.setData({ isLoading: true });

    try {
      // 如果base64不包含前缀，添加前缀
      // 统一转换为jpg格式
      const imageData = base64.startsWith('data:image') ? base64.replace(/^data:image\/[^;]+/, 'data:image/jpeg') : `data:image/jpeg;base64,${base64}`;
      
      this.setData({
        imageUrl: imageData,
        isLoading: false
      });
    } catch (error) {
      wx.showToast({
        title: 'base64格式错误',
        icon: 'none'
      });
      this.setData({ isLoading: false });
    }
  },

  saveImage() {
    if (!this.data.imageUrl) {
      wx.showToast({
        title: '请先转换图片',
        icon: 'none'
      });
      return;
    }

    this.setData({ isLoading: true });

    // 将base64转为临时文件
    const fs = wx.getFileSystemManager();
    const filePath = `${wx.env.USER_DATA_PATH}/temp_image.jpg`;
    
    try {
      // 去除base64前缀
      const base64Data = this.data.imageUrl.split(',')[1];
      fs.writeFileSync(filePath, base64Data, 'base64');

      // 保存图片到相册
      wx.saveImageToPhotosAlbum({
        filePath: filePath,
        success: () => {
          wx.showToast({
            title: '保存成功',
            icon: 'success'
          });
        },
        fail: () => {
          wx.showToast({
            title: '保存失败',
            icon: 'none'
          });
        },
        complete: () => {
          this.setData({ isLoading: false });
          // 删除临时文件
          fs.unlink({
            filePath: filePath,
            fail: () => {}
          });
        }
      });
    } catch (error) {
      wx.showToast({
        title: '图片处理失败',
        icon: 'none'
      });
      this.setData({ isLoading: false });
    }
  }
}); // 删除多余的括号，只保留一个闭合括号